function norm(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/ё/g, "е")
    .replace(/ґ/g, "г")
    .replace(/[ʼ’‘`´]/g, "'")
    .replace(/[“”"«»]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizePhrase(value) {
  return norm(value)
    .replace(/[ʼ’‘`´']/g, " ")
    .replace(/[^a-zа-яіїє0-9]+/gi, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function containsPhrase(haystack, phrase) {
  const h = ` ${normalizePhrase(haystack)} `;
  const p = ` ${normalizePhrase(phrase)} `;
  return Boolean(p.trim()) && h.includes(p);
}

function getNoteTerms(canonicalNote) {
  return NOTE_DICTIONARY[canonicalNote] || [];
}

function detectNotesInText(text) {
  const found = [];
  const seen = new Set();
  for (const [canonical, terms] of Object.entries(NOTE_DICTIONARY)) {
    const matchedTerms = (terms || []).filter((term) => containsPhrase(text, term));
    if (!matchedTerms.length) continue;
    if (seen.has(canonical)) continue;
    seen.add(canonical);
    found.push({ canonical, terms: matchedTerms });
  }
  // More specific/longer notes first: "рожевий перець" before "перець".
  return found.sort((a, b) => {
    const al = Math.max(...a.terms.map((x) => normalizePhrase(x).length));
    const bl = Math.max(...b.terms.map((x) => normalizePhrase(x).length));
    return bl - al;
  });
}

module.exports = {
  BASE_DB_NOTES,
  NOTE_DICTIONARY,
  norm,
  normalizePhrase,
  containsPhrase,
  getNoteTerms,
  detectNotesInText,
};
